async function searchUsers(filters: Record<string, string>) {
  const results: User[] = [];
  
  if (filters.id) {
    const entry = await kv.get<User>(["users", filters.id]);
    if (entry.value) results.push(entry.value);
    return results;
  }
  
  if (filters.email) {
    const userIdEntry = await kv.get<string>(["users", "by_email", filters.email]);
    if (userIdEntry.value) {
      const entry = await kv.get<User>(["users", userIdEntry.value]);
      if (entry.value) results.push(entry.value);
    }
    return results;
  }
  
  let keyPrefix: Deno.KvKey = ["users"];
  
  if (filters.city) {
    keyPrefix = ["users", "by_city", filters.city];
  } else if (filters.country) {
    keyPrefix = ["users", "by_country", filters.country];
  } else if (filters.role) {
    keyPrefix = ["users", "by_role", filters.role];
  } else if (filters.status) {
    keyPrefix = ["users", "by_status", filters.status];
  }
  
  const iter = kv.list<User>({ prefix: keyPrefix });
  
  for await (const entry of iter) {
    if (entry.key[0] === "users" && entry.key[1] !== "by_email" && 
        entry.key[1] !== "by_city" && entry.key[1] !== "by_country" && 
        entry.key[1] !== "by_role" && entry.key[1] !== "by_status") {
      if (entry.value) results.push(entry.value);
    }
  }
  
  return applyAdditionalFilters(results, filters);
}

