function applyAdditionalFilters<T extends Record<string, any>>(
  results: T[], 
  filters: Record<string, string>
): T[] {
  return results.filter(item => {
    for (const [key, value] of Object.entries(filters)) {
      if (item[key] !== undefined) {
        if (typeof item[key] === 'number') {
          if (item[key] !== Number(value)) return false;
        } else if (typeof item[key] === 'string') {
          if (item[key].toLowerCase() !== value.toLowerCase()) return false;
        } else {
          if (item[key] !== value) return false;
        }
      }
    }
    return true;
  });
}

async function deleteUser(userId: string) {
  const userEntry = await kv.get<User>(["users", userId]);
  if (!userEntry.value) return false;
  
  const user = userEntry.value;
  await kv.delete(["users", userId]);
  await kv.delete(["users", "by_email", user.email]);
  await kv.delete(["users", "by_city", user.city, userId]);
  await kv.delete(["users", "by_country", user.country, userId]);
  await kv.delete(["users", "by_role", user.role, userId]);
  await kv.delete(["users", "by_status", user.status, userId]);
  return true;
}

